PASS = 625

# 0 empty
# 1 p1 general, 2 p1 infantry, 3 p1 cavalry
# 4 p2 general, 5 p2 infantry, 6 p2 cavalry

_MOVES = {
    1: [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],
    2: [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],
    3: [(0, 3), (1, 2), (2, 1), (3, 0)],
}

_OWNER = {1: 1, 2: 1, 3: 1, 4: 2, 5: 2, 6: 2}
_TYPE = {1: 1, 2: 2, 3: 3, 4: 1, 5: 2, 6: 3}


def initial_state() -> dict:
    board = [0] * 26
    board[0:5] = [3, 2, 1, 2, 3]
    board[20:25] = [6, 5, 4, 5, 6]
    board[25] = 0
    return {"board": board, "current_player": 1}


def _in_bounds(r: int, c: int) -> bool:
    return 0 <= r < 5 and 0 <= c < 5


def _has_general(board: list[int], player: int) -> bool:
    return (1 if player == 1 else 4) in board[:25]


def _winner_by_general(board: list[int]) -> int | None:
    p1 = _has_general(board, 1)
    p2 = _has_general(board, 2)
    if p1 and not p2:
        return 1
    if p2 and not p1:
        return 2
    return None


