    board = state["board"]
    player = state["current_player"]
    actions = []

    for frm in range(25):
        piece = board[frm]
        if piece == 0 or _OWNER[piece] != player:
            continue
        r, c = divmod(frm, 5)
        ptype = _TYPE[piece]
        for dr, dc in _MOVES[ptype]:
            if player == 2:
                dr = -dr
            nr, nc = r + dr, c + dc
            if not _in_bounds(nr, nc):
                continue
            to = nr * 5 + nc
            target = board[to]
            if target != 0 and _OWNER[target] == player:
                continue
            actions.append(frm * 25 + to)

    return actions if actions else [PASS]


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]

    if action == PASS:
        new_board[25] = board[25] + 1
        return {"board": new_board, "current_player": 3 - player}

    frm, to = divmod(action, 25)
    piece = new_board[frm]
    new_board[frm] = 0
    new_board[to] = piece
    new_board[25] = board[25] + 1
    return {"board": new_board, "current_player": 3 - player}


def is_terminal(state: dict) -> bool:
    board = state["board"]
    if _winner_by_general(board) is not None:
        return True
    return board[25] >= 100


def returns(state: dict) -> dict:
    board = state["board"]
    winner = _winner_by_general(board)

    if winner == 1:
        return {1: 1.0, 2: -1.0}
    if winner == 2:
        return {1: -1.0, 2: 1.0}
    if board[25] >= 100:
        return {1: 0.0, 2: 0.0}
    return {1: 0.0, 2: 0.0}

