OFFSETS = {
    P1_GENERAL: [(1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2)],
    P1_INFANTRY: [(1, 0), (2, 0), (1, -1), (1, 1), (-1, 0)],
    P1_CAVALRY: [(0, 3), (1, 2), (2, 1), (3, 0)],
