    }


def _piece_owner(piece: int) -> int:
    if piece in (1, 2, 3):
        return 1
    if piece in (4, 5, 6):
        return 2
    return 0


def _coords(index: int) -> tuple[int, int]:
    return divmod(index, 5)


def _index(r: int, c: int) -> int:
    return r * 5 + c


def _moves_for_piece(piece: int, player: int) -> list[tuple[int, int]]:
    if piece == 0:
        return []
    if piece in (P1_GENERAL, P2_GENERAL):
        base = OFFSETS[P1_GENERAL]
    elif piece in (P1_INFANTRY, P2_INFANTRY):
        base = OFFSETS[P1_INFANTRY]
    elif piece in (P1_CAVALRY, P2_CAVALRY):
        base = OFFSETS[P1_CAVALRY]
    else:
        return []

    if player == 1:
        return base
    return [(-dr, dc) for dr, dc in base]


def legal_actions(state: dict) -> list[int]:
    board = state["board"]
    player = state["current_player"]
    actions: list[int] = []

    for from_idx in range(BOARD_SIZE):
        piece = board[from_idx]
        if _piece_owner(piece) != player:
            continue

        fr, fc = _coords(from_idx)
        for dr, dc in _moves_for_piece(piece, player):
            tr, tc = fr + dr, fc + dc
            if 0 <= tr < 5 and 0 <= tc < 5:
                to_idx = _index(tr, tc)
                dest = board[to_idx]
                if _piece_owner(dest) != player:
                    actions.append(from_idx * 25 + to_idx)

    return [PASS] if not actions else actions


def apply_action(state: dict, action: int) -> dict:
    board = state["board"]
    player = state["current_player"]
    new_board = board[:]

    if action != PASS:
        from_idx, to_idx = divmod(action, 25)
        moving = new_board[from_idx]
        new_board[from_idx] = 0
        new_board[to_idx] = moving

    new_board[25] = board[25] + 1
    return {"board": new_board, "current_player": 2 if player == 1 else 1}


def _general_alive(board: list[int], general_piece: int) -> bool:
    return general_piece in board[:25]


def is_terminal(state: dict) -> bool:
    board = state["board"]
    ply = board[25]
    p1_general_alive = _general_alive(board, P1_GENERAL)
    p2_general_alive = _general_alive(board, P2_GENERAL)
    return (not p1_general_alive) or (not p2_general_alive) or ply >= 100


def returns(state: dict) -> dict:
    board = state["board"]
    p1_general_alive = _general_alive(board, P1_GENERAL)
    p2_general_alive = _general_alive(board, P2_GENERAL)

    if not is_terminal(state):
        return {1: 0.0, 2: 0.0}

    # Winner is determined solely by which general is missing when terminal.
    # If both are present and ply limit is reached, it's a draw.
    # If both are absent, prefer the side whose move caused terminal is not
    # recoverable from state, so treat as draw unless the state is otherwise
    # clearly won by one side.
    if p1_general_alive and not p2_general_alive:
        return {1: 1.0, 2: -1.0}
    if p2_general_alive and not p1_general_alive:
        return {1: -1.0, 2: 1.0}
    return {1: 0.0, 2: 0.0}

