def _winner(board: list[int]):
    has_p1_general = False
    has_p2_general = False
    for i in range(25):
        v = board[i]
        if v == 1:
            has_p1_general = True
        elif v == 4:
            has_p2_general = True

    if has_p1_general and not has_p2_general:
        return 1
    if has_p2_general and not has_p1_general:
        return 2
    return None


def _piece_moves(board: list[int], player: int, frm: int, piece: int) -> list[int]:
    r = frm // 5
    c = frm % 5
    own_pieces = {1, 2, 3} if player == 1 else {4, 5, 6}

    if piece == 1 or piece == 4:
        offsets = ((1, 0), (-1, 0), (0, 1), (0, -1), (0, -2), (0, 2))
    elif piece == 2 or piece == 5:
        offsets = ((1, 0), (2, 0), (1, -1), (1, 1), (-1, 0))
        if player == 2:
            offsets = tuple((-dr, dc) for dr, dc in offsets)
    else:
        offsets = ((0, 3), (1, 2), (2, 1), (3, 0))
        signed_offsets = []
        for dr, dc in offsets:
            row_signs = (1,) if dr == 0 else (1, -1)
            col_signs = (1,) if dc == 0 else (1, -1)
            for rs in row_signs:
                for cs in col_signs:
                    ndr = dr * rs
                    ndc = dc * cs
                    if player == 2:
                        ndr = -ndr
                    signed_offsets.append((ndr, ndc))
        offsets = tuple(signed_offsets)

    moves = []
    for dr, dc in offsets:
        nr = r + dr
        nc = c + dc
        if 0 <= nr < 5 and 0 <= nc < 5:
            to = nr * 5 + nc
            if board[to] not in own_pieces:
                moves.append(to)

    return moves

